from flask import Flask, redirect, request, session, jsonify, url_for
import requests
import os

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', 'your-secret-key-change-in-production')

# OAuth 2.0 Configuration
OAUTH_CONFIG = {
    'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your-client-secret'),
    'authorization_url': os.environ.get('OAUTH_AUTH_URL', 'https://authorization-server.example.com/authorize'),
    'token_url': os.environ.get('OAUTH_TOKEN_URL', 'https://authorization-server.example.com/token'),
    'userinfo_url': os.environ.get('OAUTH_USERINFO_URL', 'https://authorization-server.example.com/userinfo'),
    'redirect_uri': os.environ.get('OAUTH_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': os.environ.get('OAUTH_SCOPE', 'openid profile email'),
}


@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({
            'message': 'You are logged in!',
            'logged_in': True,
            'links': {
                'profile': '/profile',
                'logout': '/logout'
            }
        })
    return jsonify({
        'message': 'Welcome! Please log in.',
        'logged_in': False,
        'links': {
            'login': '/login'
        }
    })


@app.route('/login')
def login():
    authorization_url = (
        f"{OAUTH_CONFIG['authorization_url']}"
        f"?response_type=code"
        f"&client_id={OAUTH_CONFIG['client_id']}"
        f"&redirect_uri={OAUTH_CONFIG['redirect_uri']}"
        f"&scope={OAUTH_CONFIG['scope']}"
    )

    return redirect(authorization_url)


@app.route('/callback')
def callback():
    # Check for errors returned by the authorization server
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        return jsonify({
            'error': error,
            'error_description': error_description
        }), 400

    # Get the authorization code from the query parameters
    authorization_code = request.args.get('code')
    if not authorization_code:
        return jsonify({'error': 'No authorization code received'}), 400

    # Exchange the authorization code for an access token
    token_data = {
        'grant_type': 'authorization_code',
        'code': authorization_code,
        'redirect_uri': OAUTH_CONFIG['redirect_uri'],
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret'],
    }

    token_headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json',
    }

    try:
        token_response = requests.post(
            OAUTH_CONFIG['token_url'],
            data=token_data,
            headers=token_headers,
            timeout=30
        )

        if token_response.status_code != 200:
            return jsonify({
                'error': 'Failed to exchange authorization code for token',
                'status_code': token_response.status_code,
                'details': token_response.text
            }), 500

        token_json = token_response.json()

        # Store tokens in the session
        session['access_token'] = token_json.get('access_token')

        if 'refresh_token' in token_json:
            session['refresh_token'] = token_json.get('refresh_token')

        if 'id_token' in token_json:
            session['id_token'] = token_json.get('id_token')

        if 'expires_in' in token_json:
            session['token_expires_in'] = token_json.get('expires_in')

        if 'token_type' in token_json:
            session['token_type'] = token_json.get('token_type')

        return redirect(url_for('index'))

    except requests.exceptions.Timeout:
        return jsonify({'error': 'Token request timed out'}), 504
    except requests.exceptions.ConnectionError:
        return jsonify({'error': 'Could not connect to authorization server'}), 502
    except requests.exceptions.RequestException as e:
        return jsonify({'error': f'Token request failed: {str(e)}'}), 500
    except ValueError:
        return jsonify({'error': 'Invalid JSON response from token endpoint'}), 500


@app.route('/profile')
def profile():
    access_token = session.get('access_token')
    if not access_token:
        return redirect(url_for('login'))

    try:
        userinfo_headers = {
            'Authorization': f"Bearer {access_token}",
            'Accept': 'application/json',
        }

        userinfo_response = requests.get(
            OAUTH_CONFIG['userinfo_url'],
            headers=userinfo_headers,
            timeout=30
        )

        if userinfo_response.status_code == 401:
            # Token might be expired, clear session and redirect to login
            session.clear()
            return redirect(url_for('login'))

        if userinfo_response.status_code != 200:
            return jsonify({
                'error': 'Failed to fetch user info',
                'status_code': userinfo_response.status_code
            }), 500

        user_info = userinfo_response.json()
        return jsonify({
            'message': 'User profile',
            'user': user_info
        })

    except requests.exceptions.RequestException as e:
        return jsonify({'error': f'Failed to fetch user info: {str(e)}'}), 500


@app.route('/logout')
def logout():
    session.clear()
    return jsonify({
        'message': 'You have been logged out successfully.',
        'links': {
            'login': '/login',
            'home': '/'
        }
    })


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)